const crypto = require('crypto');
const N8N_WEBHOOK_SECRET = '3e724d3f5e8587982aa19768d1eb717de56ab6798e4713b28c6c372d7c89fc3b';
const body = $input.first().json.body;
const rawBody = typeof body === 'string' ? body : JSON.stringify(body);
const sigHeader = $input.first().json.headers['x-signature-256'] || '';
if (!sigHeader.startsWith('sha256=')) throw new Error('Missing or malformed X-Signature-256 header');
const receivedSig = sigHeader.slice('sha256='.length);
const computedSig = crypto.createHmac('sha256', N8N_WEBHOOK_SECRET).update(rawBody, 'utf8').digest('hex');
if (!crypto.timingSafeEqual(Buffer.from(receivedSig, 'hex'), Buffer.from(computedSig, 'hex'))) throw new Error('HMAC mismatch');
const payload = typeof body === 'string' ? JSON.parse(body) : body;
return [{ json: payload }];

const payload = $input.first().json;
const fileUrl = (payload.publicationFileUrl || '').toLowerCase().split('?')[0];
let ext = '';
if (fileUrl.endsWith('.pdf')) ext = 'pdf';
else if (fileUrl.endsWith('.docx') || fileUrl.endsWith('.doc')) ext = 'docx';
else if (fileUrl.endsWith('.md')) ext = 'md';
else if (fileUrl.endsWith('.txt')) ext = 'txt';
else throw new Error('Unsupported file type: ' + fileUrl);
let buf;
try { buf = await this.helpers.getBinaryDataBuffer(0, 'data'); } catch (err) { throw new Error('Could not load binary: ' + (err.message || err)); }
if (!buf || buf.length === 0) throw new Error('Empty binary buffer.');
let extractedText = '';
if (ext === 'md' || ext === 'txt') { extractedText = buf.toString('utf8'); }
else if (ext === 'docx') {
  const raw = buf.toString('utf8', 0, Math.min(buf.length, 2_000_000));
  const runs = raw.match(/<w:t[^>]*>([^<]+)<\/w:t>/g) || [];
  extractedText = runs.map(t => t.replace(/<[^>]+>/g, '')).filter(t => t.trim().length > 0).join(' ');
} else {
  const raw = buf.toString('latin1');
  const streams = [];
  const re = /stream[\r\n]([\s\S]*?)[\r\n]endstream/g;
  let m;
  while ((m = re.exec(raw)) !== null) streams.push(m[1]);
  const parts = [];
  for (const s of streams) {
    const inP = s.match(/\(([^)]{3,})\)/g) || [];
    for (const t of inP) {
      const c = t.slice(1, -1).replace(/\\n/g, ' ').replace(/\\r/g, ' ').replace(/\\t/g, ' ').trim();
      if (c.length > 2) parts.push(c);
    }
  }
  extractedText = parts.join(' ');
}
if (extractedText.length > 8000) extractedText = extractedText.slice(0, 8000) + '\n\n[Zkraceno.]';
if (!extractedText || extractedText.trim().length < 50) extractedText = '[Extrakce textu se nezdarila.]';
return [{ json: { ...payload, extractedText, extractionMethod: ext } }];

