const items = $input.all().map(i => i.json);
const relevant = items.filter(it => it.relevant === true);
const webhookCtx = $('Verify HMAC').first().json;
const opener = $('Layperson Opener').first().json.output;
const extracted = $('Extract Text').first().json.extractedText;
const horizonMap = { '1m': 'Okamžitě', '3m': 'Do 3 měsíců', '6-12m': 'Do 12 měsíců', '1y+': 'Více než rok', 'Okamzite': 'Okamžitě', 'Do 3 mesicu': 'Do 3 měsíců', 'Do 12 mesicu': 'Do 12 měsíců', 'Vice nez rok': 'Více než rok' };
const tx = (h) => horizonMap[h] || (['Okamžitě','Do 3 měsíců','Do 12 měsíců','Více než rok'].indexOf(h) !== -1 ? h : 'Do 3 měsíců');
const perNaceContent = {};
const naceSectors = [];
for (const it of relevant) {
  if (!Array.isArray(it.insights) || !Array.isArray(it.actions)) continue;
  if (it.insights.length === 0 || it.actions.length === 0) continue;
  naceSectors.push(it.nace);
  perNaceContent[it.nace] = {
    observations: it.insights.slice(0, 4).map((o, i) => ({
      headline: String(o.headline || ('Pozorovani ' + (i+1))).slice(0, 80),
      body: String(o.body || ''),
      time_horizon: horizonMap[o.time_horizon] || (['Okamžitě','Do 3 měsíců','Do 12 měsíců','Více než rok'].indexOf(o.time_horizon) !== -1 ? o.time_horizon : 'Do 3 měsíců'),
      is_email_teaser: typeof o.is_email_teaser === 'boolean' ? o.is_email_teaser : (i === 0),
    })),
    closing_actions: it.actions.slice(0, 4).map((a, i) => ({
      action_text: String(a.action_text || ''),
      time_horizon: tx(a.time_horizon),
      paired_observation_index: typeof a.paired_observation_index === 'number' ? a.paired_observation_index : i,
    })),
  };
}
const now = new Date();
const M = ['Leden','Unor','Brezen','Duben','Kveten','Cerven','Cervenec','Srpen','Zari','Rijen','Listopad','Prosinec'];
const publicationMonth = M[now.getMonth()] + ' ' + now.getFullYear();
const isoMonth = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0');
const dash = String.fromCharCode(8212);
const primaryNace = (typeof webhookCtx.primaryNace === 'string' && webhookCtx.primaryNace.length > 0) ? webhookCtx.primaryNace : (naceSectors[0] || null);
const callbackPayload = {
  jobId: webhookCtx.jobId,
  status: 'done',
  naceSectors,
  primaryNace,
  publicationMonth,
  publicationMonthIso: isoMonth,
  title: 'Sektorova analyza ' + dash + ' ' + publicationMonth,
  publication: { heading: 'Sektorova analyza', opener_markdown: String(opener || ''), full_text_markdown: String(extracted || ''), source: 'Ekonomicke a strategicke analyzy Ceske sporitelny ' + dash + ' ' + publicationMonth },
  perNaceContent,
  diagnostics: { total: items.length, relevant_count: naceSectors.length, dropped: items.filter(it => !it.relevant).map(it => ({ nace: it.nace, reason: it.reason })) },
};
const passedGates = items.filter(it => it.relevant === true).length;
if (passedGates > 0 && naceSectors.length < passedGates) {
  throw new Error(
    `Tag drop: ${passedGates} gates passed but only ${naceSectors.length} tagged. ` +
    `items=${JSON.stringify(items.map(i => ({nace: i.nace, relevant: i.relevant, hasInsights: Array.isArray(i.insights), hasActions: Array.isArray(i.actions)})))}`
  );
}
return [{ json: { callbackPayload, callbackUrl: webhookCtx.callbackUrl, jobId: webhookCtx.jobId } }];

const crypto = require('crypto');
const N8N_CALLBACK_SECRET = '3e724d3f5e8587982aa19768d1eb717de56ab6798e4713b28c6c372d7c89fc3b';
const data = $input.first().json;
const bodyStr = JSON.stringify(data.callbackPayload);
const sig = crypto.createHmac('sha256', N8N_CALLBACK_SECRET).update(bodyStr, 'utf8').digest('hex');
return [{ json: { callbackUrl: data.callbackUrl, callbackBody: bodyStr, signatureHeader: 'sha256=' + sig, jobId: data.jobId, naceSectors: data.callbackPayload.naceSectors, diagnostics: data.callbackPayload.diagnostics } }];
